import { readFileSync } from "node:fs";
import { resolve } from "node:path";
import { defineConfig } from "vitepress";

interface SidebarItem {
  text: string;
  link?: string;
  collapsed?: boolean;
  items?: SidebarItem[];
}

/**
 * Load the sidebar generated by typedoc-vitepress-theme and normalise its links so VitePress
 * can match them. The plugin emits Windows-flavoured paths like
 * `/docs-site\\api/classes\\Foo.md` — strip the docs root prefix, swap backslashes, and drop
 * the `.md` extension (we run with `cleanUrls: true`).
 */
function loadApiSidebar(): SidebarItem[] {
  const sidebarFile = resolve(__dirname, "../api/typedoc-sidebar.json");
  let raw: SidebarItem[];
  try {
    raw = JSON.parse(readFileSync(sidebarFile, "utf8")) as SidebarItem[];
  } catch {
    return [];
  }
  const normalize = (item: SidebarItem): SidebarItem => {
    const next: SidebarItem = { ...item };
    if (next.link !== undefined) {
      let link = next.link.replace(/\\/g, "/");
      link = link.replace(/^\/?docs-site\/api\//, "/api/");
      link = link.replace(/\.md$/, "");
      next.link = link;
    }
    if (next.items) next.items = next.items.map(normalize);
    return next;
  };
  return raw.map(normalize);
}

